    ('(?i)(?:sampling_createMessage|create_message)\\s*(?::|\\s*=\\s*None|\\s*\\()', 'high', "mcp-sampling-abuse-data-extraction: Detects MCP server code that abuses the sampling capability (TV11) to extract information from the host'"),
    ('(?i)\\b(?:switch|change|select|override)\\s+(?:model|llm|backend|provider).{0,40}(?:from|to).{0,80}(?:without|no|bypass)\\s*(?:consent|approval|notice)', 'low', 'mcp-sampling-abuse-unauthorized-model-switch: Detects unauthorized model switching or sampling abuse where a malicious server directs the ho'),
    ('(?i)\\bset\\s*:\\s*[\'"]model[\'"]\\s*:\\s*[\'"][^\'"]*[\'"].{0,40}\\b(?:replace|override|override)\\s+(?:config|setting)', 'low', 'mcp-sampling-abuse-unauthorized-model-switch: Detects unauthorized model switching or sampling abuse where a malicious server directs the ho'),
    ('(?i)\\b(?:sampling|model)_(?:request|override|abuse).{0,60}(?:unauthorized|unapproved|malicious)', 'low', 'mcp-sampling-abuse-unauthorized-model-switch: Detects unauthorized model switching or sampling abuse where a malicious server directs the ho'),
    ('(?i)(?:sampling|model)\\s*[=:].{0,40}[\'"](?:http|https)://[^\'"]*[\'"]', 'low', 'mcp-sampling-abuse-model-call-hijack: Detects MCP client code that proxies sampling requests to an attacker-controlled endpoint, hijacking m'),
    ('(?i)(?:url|endpoint|uri)\\s*[=:].{0,40}[\'"](?:http|https)://[^\'"]*[\'"]?.{0,40}(?:sampling|model)', 'low', 'mcp-sampling-abuse-model-call-hijack: Detects MCP client code that proxies sampling requests to an attacker-controlled endpoint, hijacking m'),
    ('(?i)\x08sampling_abuse\x08', 'low', 'mcp-sampling-abuse-unauthorized-model-call-scanner: Detects unauthorized sampling or model calls via MCP sampling primitives that could abus'),
